/**
 * Event Log — M168 Phase 3 (#1913)
 *
 * Layer 3 of the 4-layer coordination architecture (#1908). Append-only
 * JSONL event stream at ~/.local/state/orchestkit/events.jsonl shared
 * across every session on the machine. Complements Layer 1 (SQLite
 * sessions/locks) by providing a chronological broadcast bus that
 * subscribers tail via a forward-only byte cursor.
 *
 * Write semantics
 * ---------------
 * Synchronous `fs.appendFileSync(path, line, { flag: 'a' })` opens the
 * file with O_APPEND. On POSIX, writes ≤ PIPE_BUF (4096 bytes on Linux,
 * 512 bytes on macOS — we keep events well under both) are atomic when
 * appending: the kernel guarantees no torn writes between concurrent
 * appenders. Each event is serialized as a single JSON line terminated
 * by `\n`; any caller that overruns that ceiling falls back to a
 * non-atomic write but still produces valid JSONL (one event per line).
 *
 * Rotation
 * --------
 * When the active file exceeds 10 MB we move it to `events.jsonl.1`
 * (deleting any prior `.1`). One generation of rotation is enough for
 * Layer 3's read pattern — subscribers cursor forward and don't need
 * deep history. Rotation is best-effort: a failed rename leaves the
 * file in place and the next append succeeds normally.
 *
 * Cursor reads
 * ------------
 * `getTailCursor()` returns the current EOF byte offset as a string.
 * `readEventsSince(cursor)` re-opens the file, seeks past `cursor`, and
 * parses each subsequent line. Truncation / rotation between calls is
 * detected by comparing file size against cursor (`size < cursor` →
 * cursor invalid → return empty, caller can `getTailCursor()` again).
 *
 * The cursor is opaque to callers — encode/decode is owned by this
 * module. The current format is the decimal byte offset as a string.
 */

import {
  appendFileSync,
  existsSync,
  mkdirSync,
  openSync,
  readSync,
  closeSync,
  renameSync,
  statSync,
  unlinkSync,
} from 'node:fs';
import { join } from 'node:path';
import { getHomeDir } from './paths.js';

/** Event subtype literal — discriminated union tag. */
export type EventType =
  | 'goal_converged'
  | 'chain_stale'
  | 'chain_phase_changed'
  | 'session_end'
  | 'worktree_done'
  | 'pr_merged';

/** Common envelope every Event carries. */
interface EventBase {
  type: EventType;
  /** Epoch milliseconds — when the producer enqueued the event. */
  ts: number;
  /** SHA-256 short hash of the repo path (12 chars, matches analytics). */
  repo_hash: string;
  /** Session id of the producer. */
  sid: string;
}

export interface GoalConvergedEvent extends EventBase {
  type: 'goal_converged';
  condition?: string;
  status?: 'converged' | 'spun' | 'aborted';
  turn_count?: number;
}

export interface ChainStaleEvent extends EventBase {
  type: 'chain_stale';
  chain_id?: string;
  phase?: string;
  stale_for_ms: number;
}

export interface ChainPhaseChangedEvent extends EventBase {
  type: 'chain_phase_changed';
  chain_id?: string;
  from_phase?: string;
  to_phase?: string;
}

export interface SessionEndEvent extends EventBase {
  type: 'session_end';
  reason?: string;
}

export interface WorktreeDoneEvent extends EventBase {
  type: 'worktree_done';
  worktree_path?: string;
  result?: string;
}

export interface PrMergedEvent extends EventBase {
  type: 'pr_merged';
  pr_number?: number;
  branch?: string;
}

export type Event =
  | GoalConvergedEvent
  | ChainStaleEvent
  | ChainPhaseChangedEvent
  | SessionEndEvent
  | WorktreeDoneEvent
  | PrMergedEvent;

// Constants — exported for tests.
export const EVENTS_DIR = join(getHomeDir(), '.local', 'state', 'orchestkit');
export const EVENTS_PATH = join(EVENTS_DIR, 'events.jsonl');
export const ROTATED_PATH = `${EVENTS_PATH}.1`;
/** Rotation threshold — 10 MB. */
export const ROTATE_BYTES = 10 * 1024 * 1024;

/** Resolve the active log path — honors ORK_EVENTS_LOG for tests. */
function resolveLogPath(): string {
  return process.env.ORK_EVENTS_LOG || EVENTS_PATH;
}

/** Resolve the rotated `.1` companion next to the active path. */
function resolveRotatedPath(active: string): string {
  return `${active}.1`;
}

/** Resolve the directory containing the active path. */
function resolveDir(active: string): string {
  const idx = active.lastIndexOf('/');
  return idx === -1 ? '.' : active.slice(0, idx) || '/';
}

/** Ensure the parent directory exists (mode 0700, owner-only). */
function ensureDir(path: string): void {
  const dir = resolveDir(path);
  if (!existsSync(dir)) {
    mkdirSync(dir, { recursive: true, mode: 0o700 });
  }
}

/**
 * Rotate the active log to `<path>.1` if it exceeds ROTATE_BYTES. Best
 * effort — never throws; never raises if the file is missing.
 */
export function rotateIfNeeded(): void {
  const path = resolveLogPath();
  let size: number;
  try {
    size = statSync(path).size;
  } catch {
    return; // missing file == nothing to rotate
  }
  if (size <= ROTATE_BYTES) return;
  const rotated = resolveRotatedPath(path);
  try {
    if (existsSync(rotated)) {
      unlinkSync(rotated);
    }
    renameSync(path, rotated);
  } catch {
    // best-effort — leave file in place if rotation fails
  }
}

/**
 * Append a single event to the log. Synchronous (hooks are sync).
 * Failure is swallowed — events are best-effort telemetry.
 */
export function appendEvent(event: Event): void {
  const path = resolveLogPath();
  ensureDir(path);
  try {
    appendFileSync(path, `${JSON.stringify(event)}\n`, { flag: 'a' });
  } catch {
    // best-effort — don't block the hook
    return;
  }
  // Opportunistic rotation check after a successful append. Cost is one
  // statSync per write, amortized into the same FS cache line.
  rotateIfNeeded();
}

/**
 * Return an opaque cursor pointing at the current EOF. Callers persist
 * this cursor and pass it back to `readEventsSince()` to read the
 * delta since their last read.
 */
export function getTailCursor(): string {
  const path = resolveLogPath();
  try {
    return String(statSync(path).size);
  } catch {
    return '0';
  }
}

/**
 * Read events written since the given cursor. A null/undefined cursor
 * means "read everything." If the file shrunk below the cursor (rotated
 * or truncated), we return [] — the caller should refresh via
 * `getTailCursor()`.
 *
 * Buffer is read in 64 KB chunks; lines are reassembled across chunk
 * boundaries. Malformed lines are skipped silently.
 */
export function readEventsSince(cursor: string | null): Event[] {
  const path = resolveLogPath();
  let size: number;
  try {
    size = statSync(path).size;
  } catch {
    return [];
  }
  const start = cursor == null ? 0 : Number(cursor);
  if (!Number.isFinite(start) || start < 0) return [];
  if (size < start) return []; // rotated or truncated
  if (size === start) return [];

  let fd: number;
  try {
    fd = openSync(path, 'r');
  } catch {
    return [];
  }

  const events: Event[] = [];
  const CHUNK = 64 * 1024;
  const buf = Buffer.alloc(CHUNK);
  let pos = start;
  let remainder = '';
  try {
    while (pos < size) {
      const want = Math.min(CHUNK, size - pos);
      const n = readSync(fd, buf, 0, want, pos);
      if (n <= 0) break;
      pos += n;
      const text = remainder + buf.slice(0, n).toString('utf8');
      const lines = text.split('\n');
      remainder = lines.pop() ?? '';
      for (const line of lines) {
        if (!line) continue;
        try {
          events.push(JSON.parse(line) as Event);
        } catch {
          // malformed line — skip
        }
      }
    }
    if (remainder) {
      try {
        events.push(JSON.parse(remainder) as Event);
      } catch {
        // trailing fragment — skip
      }
    }
  } finally {
    try { closeSync(fd); } catch { /* ignore */ }
  }
  return events;
}

/** Test-only helpers. */
export const __internals = {
  resolveLogPath,
  resolveRotatedPath,
  ensureDir,
};
